import { GlobalContext } from "./context/global";
import { useSelector } from "react-redux";
import Home from "./pages/home";
import Login from "./pages/Login";
import Header from "./layouts/Header";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import ArrowBackIcon from "@mui/icons-material/ArrowBack";

export default function App() {
  const __is_authenticated = useSelector(
    (state) => state.auth.is_authenticated
  );

  const [_data, set_data] = useFetch([], {
    url: "PLAN_COMMUNE",
    method: "get",
  });

  // const [localstorage, set_localstorage] = useLocalStorage([])

  // const [_data, set_data] =useState([])
  // const [_value, set_value] = useLocalStorage("token", "")
  // localStorage.setItem("token", "51cf7433b7925830481303d0980008d988695db2");

  function getQuery(q) {
    return (window.location.search.match(
      new RegExp("[?&]" + q + "=([^&]+)")
    ) || [, null])[1];
  }

  useEffect(() => {
    if (__is_authenticated) {
    }
    return () => {};
  }, []);

  return (
    <>
      <div className="bg-slate-900 min-h-screen text-white">
        {!getQuery("is_mobile") == true && (
          <div
            className="bg-slate-900 absolute top-3 left-3 width-[60px] height-[60px] rounded-full"
            onClick={() => window.history.back()}
          >
            <ArrowBackIcon />
          </div>
        )}
        <GlobalContext.Provider value={_data}>
          <Header />
          <HashRouter>
            <Routes>
              <Route path="/" element={<Home />} />
            </Routes>
          </HashRouter>
        </GlobalContext.Provider>
      </div>
    </>
  );
}
