import { useState, useEffect } from "react";
import UserSelector from "../../components/UserSelector";
import Button from "../../components/utils/Button";
// import Select from '../../components/utils/Select'
import useFetch from "../../hooks/useFetch";
import List from "./List";
import LocalPrintshopIcon from "@mui/icons-material/LocalPrintshop";
import { format } from "date-fns";
// import { DayPicker } from 'react-day-picker';
import DatePicker from "react-date-picker";
import "react-day-picker/dist/style.css";
import Modal from "../../components/utils/Modal";
import Select from "react-select";
import Loader from "../../components/utils/Loader";
// import Input from "../../components/utils/Input";
import CloseIcon from "@mui/icons-material/Close";
import Checkbox from "@mui/material/Checkbox";
import SearchSharpIcon from "@mui/icons-material/SearchSharp";
// import TextField from "@mui/material/TextField";

const date_format = (dt) =>
  `${dt.getFullYear()}-${
    dt.getMonth() + 1 < 10 ? "0" + (dt.getMonth() + 1) : dt.getMonth() + 1
  }-${dt.getDate() < 10 ? "0" + dt.getDate() : dt.getDate()}`;
const getQuery = (q) =>
  (window.location.search.match(new RegExp("[?&]" + q + "=([^&]+)")) || [
    ,
    null,
  ])[1];

export default function Home() {
  const [_is_loading, set_is_loading] = useState(false);
  const [_user, set_user] = useFetch(
    { users_under: [] },
    { url: "CURRENT_USER", method: "get" }
  );
  const [_users, set_users] = useFetch([], { url: "ALL_USERS", method: "get" });
  const [_selected_usr, set_selected_usr] = useState([
    getQuery("user") ? getQuery("user") : _user.username,
  ]);
  const [_min_date, set_min_date] = useState(
    getQuery("date")
      ? new Date(
          parseInt(getQuery("date").slice(0, 4)),
          parseInt(getQuery("date").slice(5, 7)) - 1,
          parseInt(getQuery("date").slice(8, 10))
        )
      : new Date(Date.now() - 86400000)
  );
  const [_max_date, set_max_date] = useState(
    getQuery("date")
      ? new Date(
          parseInt(getQuery("date").slice(0, 4)),
          parseInt(getQuery("date").slice(5, 7)) - 1,
          parseInt(getQuery("date").slice(8, 10))
        )
      : new Date()
  );
  const [_statuss, set_statuss] = useState([]);
  const [_client_spec, set_client_spec] = useState([]);
  const [_source_spec, set_source_spec] = useState([]);
  const [_office, set_office] = useState(false);
  const [_attente, set_attente] = useState(false);
  const [_flag, set_flag] = useState(false);
  const [_keyword, set_keyword] = useState("");

  const [_show_filters, set_show_filters] = useState(false);

  const [_orders, set_orders] = useFetch([], {
    url: "PLANS",
    method: "get",
    params: {
      min_date: date_format(new Date()),
      max_date: date_format(new Date()),
    },
  });

  useEffect(() => {
    fetch_by_users();
    // console.log(_statuss)
    return () => {};
  }, [
    _selected_usr,
    _min_date,
    _max_date,
    _user,
    _statuss,
    _client_spec,
    _source_spec,
    _keyword,
    _office,
    _attente,
    _flag,
  ]);

  const axios = require("axios");

  //  alert(getQuery("is_mobile"))

  const fetch_by_users = () => {
    set_is_loading(true);
    axios({
      url: "PLANS",
      params: {
        user: _selected_usr.length > 0 ? _selected_usr.join(",") : "",
        status: _statuss.join(","),
        min_date: date_format(_min_date),
        max_date: date_format(_max_date),
        source: _source_spec.length > 0 ? _source_spec.join(",") : "",
        client: _client_spec.length > 0 ? _client_spec.join(",") : "",
        keyword: _keyword,
        office: _office ? "1" : "",
        attente: _attente ? "1" : "",
        flag: _flag ? "1" : "",
      },

      method: "get",
    })
      .then((res) => {
        set_is_loading(false);
        set_orders(res.data);
      })
      .catch((err) => {
        set_is_loading(false);
        console.log("err");
        setTimeout(() => fetch_by_users(), 1000);
      });
  };

  const open_print = () => {
    const link = `https://app.liliumpharma.com/orders/PDF/?min_date=${date_format(
      _min_date
    )}&max_date=${date_format(_max_date)}&user=${
      _selected_usr.length > 0
        ? _selected_usr.length > 0
          ? _selected_usr.join(",")
          : _user.username
        : _user.username
    }`;
    window.ReactNativeWebView
      ? window.ReactNativeWebView.postMessage(
          JSON.stringify({
            print: link,
          })
        )
      : window.open(link, "", "width=400, height=400");
  };

  return (
    <>
      <div className=" bg-slate-900">
        <div className="py-3 px-4  items-center gap-1">
          <div className="flex w-full items-center">
            <div className="grow text-black">
              <span className="text-white">Choisir un utilisateur</span>
              <Select
                closeMenuOnSelect={false}
                selectedOptions={[
                  { name: _user.username, value: _user.username },
                ]}
                isMulti
                options={[
                  { label: "tous", value: "" },
                  { label: _user.username, value: _user.username },
                  ..._user.users_under.map((usr) => ({
                    label: usr.username,
                    value: usr.username,
                  })),
                ]}
                onChange={(selected) =>
                  set_selected_usr(selected.map((usr) => usr.value))
                }
              />
            </div>
          </div>
          <div className="grow">
            {/* <Select
              options={[{ name: _user.username, value: _user.username }, ..._user.users_under.map(usr => ({ name: usr.username, value: usr.username }))]}
              onChange={(e) => { console.log(e.target.selectedOptions);set_selected_usr(e.target.value); }}
              multilple={true}
            /> */}
            <div className="flex items-center gap-1 py-1">
              <div>
                <div className="text-xs">du:</div>
                {/* <span className='text-xs bg-slate-500  p-1 rounded' onClick={()=>set_show_min_picker(true)}> { date_format( _min_date ) } </span> */}
                <DatePicker
                  onChange={set_min_date}
                  value={_min_date}
                  calendarIcon={null}
                  locale="fr"
                  clearIcon={null}
                />
              </div>
              <div>
                <div className="text-xs">au:</div>
                {/* <span className='text-xs bg-slate-500 text-white p-1 rounded' onClick={()=>set_show_max_picker(true)}> { date_format( _max_date ) } </span> */}
                <DatePicker
                  onChange={set_max_date}
                  value={_max_date}
                  calendarIcon={null}
                  locale="fr"
                  clearIcon={null}
                />
              </div>
              <br />
              <Checkbox
                type="checkbox"
                defaultChecked={_office}
                onChange={(e) => set_office(e.target.checked)}
                style={{ color: "#FFFFFF", marginTop: "15px" }}
              />

              <p
                style={{
                  color: "#FFFFFF",
                  marginTop: "15px",
                  fontSize: "13px",
                }}
              >
                office lilium
              </p>

              <br />

              <Checkbox
                type="checkbox"
                defaultChecked={_flag}
                onChange={(e) => set_flag(e.target.checked)}
                style={{ color: "#FFFFFF", marginTop: "15px" }}
              />
              <p
                style={{
                  color: "#FFFFFF",
                  marginTop: "15px",
                  fontSize: "13px",
                }}
              >
                En attente
              </p>

              <div className="hidden md:flex">
                <Checkbox
                  type="checkbox"
                  defaultChecked={_attente}
                  onChange={(e) => set_attente(e.target.checked)}
                  style={{ color: "#FFFFFF", marginTop: "15px" }}
                />
                <p
                  style={{
                    color: "#FFFFFF",
                    marginTop: "38%",
                    fontSize: "13px",
                  }}
                >
                  Flag
                </p>
              </div>

              <div
                onClick={() => {
                  set_show_filters(!_show_filters);
                }}
                style={{ marginLeft: "15px", marginBottom: "10px" }}
                className="hidden md:block"
              >
                <br />
                <SearchSharpIcon />
                Autres
              </div>
            </div>
          </div>
          {/* <div className='flex bg-slate-800 items-center justify-center w-[40px] h-[40px] rounded-full'>
            <LocalPrintshopIcon sx={{ ml: 1, mr: 1 }} onClick={(e) => { open_print()}} />
          </div> */}
        </div>
      </div>

      {_is_loading && (
        <div className="text-center">
          <Loader />
        </div>
      )}

      <div
        className={`w-[70%] p-3 h-full top-0 left-0 fixed bg-slate-800 z-[999] ${
          _show_filters ? "" : "hidden"
        }`}
      >
        <div className="text-right">
          <CloseIcon onClick={() => set_show_filters(false)} />
        </div>
        <div className="text-black">
          <div className="d-flex">
            <span className="text-white">Recherche Par Mots</span>
            <div>
              <input
                id="standard-size-small"
                label="..."
                placeholder="..."
                value={_keyword}
                variant="standard"
                onChange={(e) => set_keyword(e.target.value)}
                style={{
                  border: "2px solid white",
                  color: "green",
                  fontSize: "14px",
                }}
              />
            </div>
          </div>

          <span className="text-white">status</span>
          <Select
            closeMenuOnSelect={false}
            isMulti
            options={[
              { label: "initial", value: "initial" },
              { label: "confirme", value: "confirme" },
              { label: "en cours", value: "en cours" },
              { label: "traite", value: "traite" },
            ]}
            onChange={(selected) => set_statuss(selected.map((s) => s.value))}
          />
        </div>
        <div className="text-black">
          <span className="text-white">Client</span>
          <Select
            closeMenuOnSelect={false}
            isMulti
            options={[
              { label: "pharmacie", value: "Pharmacie" },
              { label: "Gros", value: "Gros" },
              { label: "Supergros", value: "Supergros" },
            ]}
            onChange={(selected) =>
              set_client_spec(selected.map((s) => s.value))
            }
          />
        </div>
        <div className="text-black">
          <span className="text-white">Source</span>
          <Select
            closeMenuOnSelect={false}
            isMulti
            options={[
              ,
              { label: "gros", value: "Gros" },
              { label: "supergros", value: "Supergros" },
            ]}
            onChange={(selected) =>
              set_source_spec(selected.map((s) => s.value))
            }
          />
        </div>
      </div>

      <List
        orders={_orders}
        set_order={(p) =>
          set_orders(_orders.map((order) => (order.id == p.id ? p : order)))
        }
        user={_user}
        users={_users}
      />
      {/* <div className="mx-3 p-4 bg-slate-700">
          <Button loading={_is_loading} onClick={()=>validate_all()} >
              Valider Tous
          </Button>
      </div> */}
    </>
  );
}
