import React from "react";
import ArrowForwardIcon from "@mui/icons-material/ArrowForward";

export default function Status({ order, update_order_status }) {
  const order_color = (status) => {
    return {
      initial: "bg-green-500",
      confirme: "bg-green-500",
      encours: "bg-green-500",
      traite: "bg-green-500",
    }[status.replaceAll(" ", "")];
  };

  const get_next_status = () => {
    return {
      initial: "confirme",
      confirme: "en cours",
      encours: "traite",
      traite: "",
    }[order.status.replaceAll(" ", "")];
  };

  return (
    <>
      {["initial", "confirme", "en cours", "traite"].map((stat) => (
        <>
          {stat != "initial" && (
            <span className="text-xs">
              <ArrowForwardIcon fontSize="small" />
            </span>
          )}
          <span
            className={`inline-block mx-1 p-1 px-2 rounded-xl text-white ${
              order.status == stat ? order_color(order.status) : "bg-gray-800"
            }`}
            onClick={() =>
              get_next_status() == stat
                ? update_order_status()
                : order.status != "traite" &&
                  alert("  لا يمكنك تغيير حالة الطلبية  الى هذا الوضع ")
            }
          >
            {stat}
          </span>
        </>
      ))}
    </>
  );
}
