
import colors from "../../constants/colors"
import Loader from "./Loader"

const Button=({children,onClick=(e)=>{},loading=false,style}) =>  {
  return (
    <button 
      type="button"
      onClick={onClick} 
      className="w-full   hover:bg-opacity-50 text-white text-center font-bold p-3 rounded inline-flex items-center justify-center uppercase" style={{background:colors.primary}}>
         {loading ? <Loader/> :  children}
    </button>
  )
}

export default Button