import { tr } from 'date-fns/locale'
import React from 'react'
import AddTracking from './AddTracking'
import axios from "axios"

export default function Trackings({trackings, set_order,order}) {
    const delete_tracking=(tr)=>{
        // set_order({...order,tracking:order.tracking.filter(tra=>tra.date!=tr.date)})
        console.log(order.tracking.filter(tra=>tra.date!=tr.date))
        delete order.image;
        axios({
            url:`https://app.liliumpharma.com/orders/app/api/v2/front/${order.id}`,
            method:"post",
            data:{...order,tracking:order.tracking.filter(tra=>tra.date!=tr.date)}
        })
        .then(res=>{
            set_order(res.data)
        })
        .catch(err=>{
            console.log("une erreur s'est produites veuillez reessayer")
            console.log(err)
        })
    }
  return (
    <div>

            {
                order.tracking.map(tr=>
                    <div className='flex flex-wrap'>
                        <div className="border-2 border-gray-500 p-2"><DateTimeComponent  datetime={tr.date}  center={false} size="14px" inline /></div>
                        <div className="border-2 border-gray-500 p-2">{tr.type}</div>
                        <div className="border-2 border-gray-500 p-2">{tr.code}</div>
                        <div className="border-2 border-gray-500 p-2">
                                <span className='px-1 inline-block'>
                                    {tr.products.map(itm=><div className="border-2 border-gray-500 p-2">{itm.product.nom} {itm.qtt}</div>)}
                                </span>

                        </div>
                        <div className="border-2 border-gray-500 p-2">{tr.observation}</div>
                        {order.status == "en cours" && 
                            <div className="border-2 border-gray-500 p-2">
                                <a className='bg-red-500 p-1 text-sm rounded-md' onClick={()=>delete_tracking(tr)}>suprimmer</a>
                            </div>
                        }
                    </div>
                    )
            }
            {
                order.status != "traite" &&
                <AddTracking  set_order={set_order} order={order} />
            }
    </div>
  )
}



const DateTimeComponent = ({ datetime,center=true,size, inline}) => {
    const d = new Date(datetime)

    if(datetime) 
    return (
        <div className={`${ center ? "text-center" : ""} ${inline ? "inline" : "block"}`} style={{fontSize:size ? size : "8px"}}>
            <div className={`${inline ? "inline" : "block"}`}>{d.getDate()}-{d.getMonth() + 1}-{d.getFullYear()}</div>
            <div className={`${inline ? "inline" : "block"}`}>  {d.getHours()}:{d.getMinutes()}</div>
        </div>
    )
    else return (<></>)
}