const DEFAULT_STATE =  {user:{username:"Anounymous",id:0,messages:[]}};

const UserReducer = (state = DEFAULT_STATE, action = {}) => {
  switch (action.type) {
    case "SET_USER":
      return {
        ...state,
        user:action.payload,
        isLoggedIn: true
      };

    case "SET_AUTH":
      return action.payload;
  }
  return state;
};

const axios=require("axios")
export const GET_USER_INFOS=()=> async (dispatch) =>{
  console.log("getting my infos  ...")
  await axios({
    url:"VERIFY_AUTH",
  })
  .then(res=>{dispatch({ type: "SET_USER", payload:res.data }); console.log(res.data)} ) 
  .catch(err=>console.log(err))
}
export default UserReducer;