import React from 'react'
import SingleOrder from '../../components/SingleOrder'

export default function List({ orders, set_order, user, users }) {



    const get_day_name = (dt) => {
        const language = 'fr-fr';
        const options = {  weekday: 'long' };
        const today = new Date(parseInt(dt.split("-")[0]), parseInt(dt.split("-")[1])-1,parseInt(dt.split("-")[2])).toLocaleString(language, options)
        return today
    }

    return (
        <>
            <div className='grid grid-cols-1 md:grid-cols-3 gap-y-2 gap-x-2'>
                {
                    orders.map(order =>
                        <React.Fragment key={order.id}>
                            <SingleOrder order={order} set_order={set_order} current_user={user} users={users} />
                        </React.Fragment>
                    )
                }
            </div>
        </>
    )
}
