import React from 'react'

export default function Select({options,onChange,multilple=false}) {
  console.log(window.innerWidth)
  return (
    <>
        <select  
            className="p-2 rounded bg-slate-800 mb-2 w-full text-white"
            multiple={multilple}

            style={{maxHeight: multilple ?  window.innerWidth > 600 ? "auto" :  "40px" : "auto"}}
            onChange={(e)=>onChange(e)}>
            {
                options.map((v,i)=>({...v,id:i})).map(op=>(
                    <option key={op.id} value={op.value}>{op.name}</option>
                ))
            }
        </select>
    </>
  )
}
