const DEFAULT_STATE =  {is_authenticated: false};

const authReducer = (state = DEFAULT_STATE, action = {}) => {
  switch (action.type) {

    case "LOGIN":
      return {
        ...state,
        is_authenticated: true,
      };

    case "LOGOUT":
      return {
        ...state,
        is_authenticated: false,
      };
  }
  return state;
};

export default authReducer;