import {useState} from 'react'
import DatePicker from 'react-date-picker';
import Select from './utils/Select';
import Input from './utils/Input';



export default function ProductQttSelector({order, products, set_products }) {

  const [_to_add, set_to_add] = useState()


  return (
    <>

            {
                products.map(itm=>
                <div className="flex gap-2 items-center" >
                {itm.product.nom}
                    <Input 
                        placeholder={"qtt"} 
                        label={""} 
                        type={"number"} 
                        onKeyUp={e=>{
                            set_products(products.map(pr=>pr.id==itm.id ? {...pr,qtt:e.target.value} : pr ))
                        }}
                    />
                    </div>
               )
            }
    </>
  )
}
