import React from 'react'

export default function Input({ label, onChange = (e) => { }, onKeyUp = (e) => { }, initialValue = "", placeholder = "", onBlur = () => { },ref=null }) {
  return (
    <>
      <label className="capitalize">{label}</label>
      <input type="text"
        className='p-2 rounded bg-slate-800 w-full text-white input'
        onChange={onChange}
        onKeyUp={onKeyUp}
        defaultValue={initialValue}
        placeholder={placeholder}
        onBlur={() => onBlur([])}
        ref={ref}
      />
    </>
  )
}
