import axios from "axios";
import { useState } from "react";
import Select from "react-select";
import colors from "../constants/colors";
import Loader from "./utils/Loader";
import CloseIcon from "@mui/icons-material/Close";

export default function ShareToUser({ order, users, set_show_share_user }) {
  const [_user, set_user] = useState(0);
  const [_is_loading, set_is_loading] = useState(false);

  const share_user = () => {
    if (_user != 0) {
      set_is_loading(true);
      axios({
        url: `https://app.liliumpharma.com/orders/share-to-user/${order.id}`,
        method: "get",
        params: {
          user: _user,
        },
      })
        .then((res) => {
          set_is_loading(false);
          set_show_share_user(false);
        })
        .catch((err) => {
          set_is_loading(false);
          console.log("err", err);
          alert("une erreur s'est produites veuillez réessayer");
        });
    }
  };
  return (
    <>
      <div className="flex items-center gap-1 text-black w-full">
        {" "}
        {/* Ajoutez w-full pour que le div prenne toute la largeur */}
        <Select
          closeMenuOnSelect={true}
          options={users.map((usr) => ({ value: usr.id, label: usr.username }))}
          onChange={(selected) => set_user(selected.value)}
          className="w-full"
        />
        <div
          className="p-1 rounded"
          style={{ background: colors.primary }}
          onClick={share_user}
        >
          {_is_loading ? <Loader /> : "OK"}
        </div>
        <div
          className="p-1 rounded bg-red-500"
          onClick={() => set_show_share_user(false)}
        >
          <CloseIcon />
        </div>
      </div>
    </>
  );
}
